def get_airfoil_coordinates(name: str) -> List[List[float]]:
    """
    Returns a list of [x, y] coordinate pairs for the given airfoil.
    """
    # 1. Check Specialist Library first (exact or partial match)
    for key, data in SPECIAL_AIRFOILS.items():
        if key.lower() in name.lower():
            return data
            
    # 2. Check if it's a NACA airfoil
    if name.upper().startswith("NACA"):
        try:
            coords = naca_from_string(name)
            single = to_single_surface(coords)
            # Return as list of [x, y]
            return [[float(x), float(y)] for x, y in zip(single.x, single.y)]
        except Exception:
            pass
            
    # 3. Fallback (Symmetrical NACA 0012)
    try:
        coords = naca_from_string("0012")
        single = to_single_surface(coords)
        return [[float(x), float(y)] for x, y in zip(single.x, single.y)]
    except:
        return [[0.0, 0.0], [0.5, 0.05], [1.0, 0.0], [0.5, -0.05], [0.0, 0.0]]
